// frontend/src/services/api.js
// Implementación de servicio API con soporte para modo de desarrollo

// Verificar si estamos en modo de desarrollo
const isDevelopment = process.env.NODE_ENV === 'development';

// Función de ayuda para simular retrasos de red en modo de desarrollo
const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// URL base de la API
const API_BASE_URL = isDevelopment ? '' : '/api';

// Función para manejar errores de respuesta
const handleResponse = async (response) => {
  if (!response.ok) {
