    // Extraer información de los archivos para nuestra respuesta mock
    const projectId = formData.get('project');
    const year = formData.get('year');
    const startDate = formData.get('start_date');
    const endDate = formData.get('end_date');
    
    // Obtener archivos del FormData para mostrarlos en la respuesta
    const libroFiles = [];
    const sumasFiles = [];
    
    formData.getAll('libro_diario_files').forEach(file => {
      libroFiles.push({
        name: file.name,
        size: file.size
      });
    });
    
    formData.getAll('sumas_saldos_files').forEach(file => {
      sumasFiles.push({
        name: file.name, 
        size: file.size
      });
    });
    
    console.log('Modo desarrollo: Simulando carga de archivos exitosa');
    
    // Generar un ID temporal único
    const tempDir = 'mock_' + Date.now().toString();
    
    return {
      project: projectId,
      year: year,
      date_range: `${startDate} - ${endDate}`,
      libro_diario_files: libroFiles,
      sumas_saldos_files: sumasFiles,
      temp_dir: tempDir
    };
  }
  
  // En producción, hacer la solicitud real
  const response = await fetch(`${API_BASE_URL}/upload`, {
    method: 'POST',
    body: formData,
  });
  
  return handleResponse(response);
};

// Función para obtener datos de previsualización
export const getPreviewData = async (tempDir, fileType) => {
  // En modo de desarrollo, simular respuesta
  if (isDevelopment) {
